mapper.select:
SELECT t.*, w.warehouse_code AS warehouseCode, w.warehouse_name AS warehouseName, l.location_code AS locationCode, m.materiel AS materialCode, m.materiel_desc AS materialName FROM sp_warehouse_transaction t LEFT JOIN sp_warehouse w ON t.warehouse_id = w.id LEFT JOIN sp_warehouse_location l ON t.location_id = l.id LEFT JOIN sp_materile m ON t.material_id = m.id WHERE 1 = 1
AND t.request_no LIKE CONCAT('%', #{req.requestNoLike}, '%')
AND t.business_type = #{req.businessType}
AND t.direction = #{req.direction}
AND t.warehouse_id = #{req.warehouseId}
AND (m.materiel LIKE CONCAT('%', #{req.materialLike}, '%') OR m.materiel_desc LIKE CONCAT('%', #{req.materialLike}, '%'))
AND t.batch_no LIKE CONCAT('%', #{req.batchNoLike}, '%')
AND t.operate_time >= #{req.beginDate}
AND t.operate_time <= #{req.endDate}
ORDER BY t.operate_time DESC, t.update_time DESC
